#canvas-container {
  width: 100%;
  height: 100%;
  position: relative;
  overflow: hidden;
}

#info-panel {
  position: absolute;
  top: 10px;
  right: 10px;
  width: 220px;
  background: rgba(0, 0, 0, 0.75);
  border: 1px solid rgba(255, 255, 255, 0.2);
  border-radius: 8px;
  padding: 12px;
  color: #fff;
  font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
  font-size: 12px;
  pointer-events: none;
  z-index: 10;
  backdrop-filter: blur(4px);
}

.info-header h3 {
  margin: 0 0 4px 0;
  font-size: 14px;
  color: #ffd700;
}

.info-subtitle {
  margin: 0;
  color: #999;
  font-size: 10px;
}

.planet-info {
  margin-top: 8px;
}

.info-placeholder {
  color: #666;
  text-align: center;
  padding: 10px 0;
}

.planet-detail {
  animation: fadeIn 0.3s ease-in;
}

@keyframes fadeIn {
  from { opacity: 0; transform: translateY(-5px); }
  to { opacity: 1; transform: translateY(0); }
}

.planet-detail h4 {
  margin: 0 0 6px 0;
  color: #ffd700;
  font-size: 13px;
}

.planet-detail .detail-row {
  display: flex;
  justify-content: space-between;
  padding: 2px 0;
  border-bottom: 1px solid rgba(255, 255, 255, 0.1);
}

.planet-detail .detail-label {
  color: #999;
}

.planet-detail .detail-value {
  color: #fff;
  font-weight: bold;
}

.planet-detail .detail-desc {
  margin-top: 6px;
  color: #ccc;
  font-size: 11px;
  line-height: 1.4;
}

#controls-hint {
  position: absolute;
  bottom: 10px;
  left: 50%;
  transform: translateX(-50%);
  background: rgba(0, 0, 0, 0.6);
  color: #aaa;
  padding: 6px 12px;
  border-radius: 4px;
  font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
  font-size: 11px;
  z-index: 10;
  pointer-events: none;
  white-space: nowrap;
}

.label {
  color: #fff;
  font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
  font-size: 12px;
  font-weight: bold;
  text-shadow: 0 0 4px rgba(0, 0, 0, 0.8), 0 0 8px rgba(0, 0, 0, 0.5);
  pointer-events: none;
  white-space: nowrap;
}

