      type: 'Ice Giant',
      diameter: '49,528 km',
      dayLength: '16.1 hours',
      moons: '16',
      temperature: '~-200°C',
      description: 'The most distant planet. Has the strongest winds in the Solar System (up to 2,100 km/h).'
    }
  ];

  // Texture URLs (Wikimedia Commons, CC BY 4.0)
  const TEXTURE_URLS = {
    sun: 'https://upload.wikimedia.org/wikipedia/commons/c/cb/Solarsystemscope_texture_2k_sun.jpg',
    mercury: 'https://upload.wikimedia.org/wikipedia/commons/9/92/Solarsystemscope_texture_2k_mercury.jpg',
    venus: 'https://upload.wikimedia.org/wikipedia/commons/4/40/Solarsystemscope_texture_2k_venus_surface.jpg',
    earth: 'https://upload.wikimedia.org/wikipedia/commons/c/c3/Solarsystemscope_texture_2k_earth_daymap.jpg',
    mars: 'https://upload.wikimedia.org/wikipedia/commons/4/46/Solarsystemscope_texture_2k_mars.jpg',
    jupiter: 'https://upload.wikimedia.org/wikipedia/commons/b/be/Solarsystemscope_texture_2k_jupiter.jpg',
    saturn: 'https://upload.wikimedia.org/wikipedia/commons/1/1e/Solarsystemscope_texture_8k_saturn.jpg',
    uranus: 'https://upload.wikimedia.org/wikipedia/commons/9/95/Solarsystemscope_texture_2k_uranus.jpg',
    neptune: 'https://upload.wikimedia.org/wikipedia/commons/1/1e/Solarsystemscope_texture_2k_neptune.jpg',
    stars: 'https://upload.wikimedia.org/wikipedia/commons/0/0e/Solarsystemscope_texture_2k_stars_milky_way.jpg'
  };

  // ============================================================
  // Globals
  // ============================================================
  let scene, camera, renderer, controls;
  let sunMesh, planets = [], labels = [], orbitalLines = [];
  let raycaster, mouse;
  let selectedPlanet = null;
  let clock;
  const textureLoader = new THREE.TextureLoader();

  // ============================================================
  // Initialization
  // ============================================================
  function init() {
    clock = new THREE.Clock();
    raycaster = new THREE.Raycaster();
    mouse = new THREE.Vector2();

    // Scene
    scene = new THREE.Scene();
    scene.background = new THREE.Color(0x000005);

    // Camera
    camera = new THREE.PerspectiveCamera(60, container.clientWidth / container.clientHeight, 0.1, 1000);
    camera.position.set(15, 12, 15);
    camera.lookAt(0, 0, 0);

    // Renderer
    renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setSize(container.clientWidth, container.clientHeight);
    renderer.setPixelRatio(window.devicePixelRatio);
    document.getElementById('canvas-container').appendChild(renderer.domElement);

    // OrbitControls
    initControls();

    // Lighting
    setupLighting();

    // Starfield
    createStarfield();

    // Sun
    createSun();

    // Planets
    PLANET_DATA.forEach(function(data, index) {
      createPlanet(data, index);
    });

    // Click handler
    renderer.domElement.addEventListener('click', onCanvasClick);

    // Resize handler
    window.addEventListener('resize', onResize);
  }

  function initControls() {
    // Dynamic import of OrbitControls
    import('https://cdn.jsdelivr.net/npm/three@0.160.0/examples/jsm/controls/OrbitControls.js').then(function(module) {
      const OrbitControls = module.OrbitControls;
      controls = new OrbitControls(camera, renderer.domElement);
      controls.enableDamping = true;
      controls.dampingFactor = 0.05;
      controls.minDistance = 3;
      controls.maxDistance = 80;
    }).catch(function(err) {
      console.warn('OrbitControls failed to load:', err);
    });
  }

  function setupLighting() {
    // Sun point light (creates day/night sides on planets)
    const sunLight = new THREE.PointLight(0xffffff, 2, 100);
    sunLight.position.set(0, 0, 0);
    scene.add(sunLight);

    // Ambient light (so dark side isn't completely black)
    const ambientLight = new THREE.AmbientLight(0x222233, 0.3);
    scene.add(ambientLight);
  }

  // ============================================================
  // Starfield
  // ============================================================
  function createStarfield() {
    const starsGeometry = new THREE.BufferGeometry();
    const starCount = 5000;
    const positions = new Float32Array(starCount * 3);
    const colors = new Float32Array(starCount * 3);

    for (var i = 0; i < starCount; i++) {
      var i3 = i * 3;
      var radius = 100 + Math.random() * 200;
      var theta = Math.random() * Math.PI * 2;
      var phi = Math.acos(2 * Math.random() - 1);
      positions[i3] = radius * Math.sin(phi) * Math.cos(theta);
      positions[i3 + 1] = radius * Math.sin(phi) * Math.sin(theta);
      positions[i3 + 2] = radius * Math.cos(phi);

      // Slight color variation
      var brightness = 0.5 + Math.random() * 0.5;
      var colorShift = Math.random();
      if (colorShift > 0.9) {
        // Blue-ish stars
        colors[i3] = brightness * 0.8;
        colors[i3 + 1] = brightness * 0.85;
        colors[i3 + 2] = brightness;
      } else if (colorShift > 0.8) {
        // Red-ish stars
        colors[i3] = brightness;
        colors[i3 + 1] = brightness * 0.85;
        colors[i3 + 2] = brightness * 0.7;
      } else {
        // White stars
        colors[i3] = brightness;
        colors[i3 + 1] = brightness;
        colors[i3 + 2] = brightness;
      }
    }

    starsGeometry.setAttribute('position', new THREE.BufferAttribute(positions, 3));
    starsGeometry.setAttribute('color', new THREE.BufferAttribute(colors, 3));

    var starsMaterial = new THREE.PointsMaterial({
      size: 0.3,
      vertexColors: true,
      sizeAttenuation: true,
      transparent: true,
      opacity: 0.8
    });

    var starField = new THREE.Points(starsGeometry, starsMaterial);
    scene.add(starField);
  }

  // ============================================================
  // Sun
  // ============================================================
  function createSun() {
    var sunGeometry = new THREE.SphereGeometry(1.5, 64, 64);
    var sunMaterial = new THREE.MeshBasicMaterial({
      map: textureLoader.load(TEXTURE_URLS.sun, function() {}, function() {
        console.warn('Sun texture failed, using fallback color');
      }),
      color: 0xffdd44
    });
    sunMesh = new THREE.Mesh(sunGeometry, sunMaterial);
    scene.add(sunMesh);

    // Sun glow (outer sprite)
    var glowGeometry = new THREE.SphereGeometry(2.2, 32, 32);
    var glowMaterial = new THREE.MeshBasicMaterial({
      color: 0xffaa00,
      transparent: true,
      opacity: 0.15,
      side: THREE.BackSide
    });
    var glowMesh = new THREE.Mesh(glowGeometry, glowMaterial);
    scene.add(glowMesh);

    // Second glow layer
    var glow2Geometry = new THREE.SphereGeometry(2.8, 32, 32);
    var glow2Material = new THREE.MeshBasicMaterial({
      color: 0xff8800,
      transparent: true,
      opacity: 0.08,
      side: THREE.BackSide
    });
    var glow2Mesh = new THREE.Mesh(glow2Geometry, glow2Material);
    scene.add(glow2Mesh);
  }

  // ============================================================
  // Planets
  // ============================================================
  function createPlanet(data, index) {
    // Create planet mesh
    var geometry = new THREE.SphereGeometry(data.radius, 32, 32);
    var material;

    // Try to load texture, fallback to color
    var textureUrl = TEXTURE_URLS[data.name.toLowerCase()];
    if (textureUrl) {
      material = new THREE.MeshStandardMaterial({
        map: textureLoader.load(textureUrl, function() {}, function() {
          console.warn(data.name + ' texture failed, using fallback color');
        }),
        color: data.color,
        roughness: 0.8,
        metalness: 0.1
      });
    } else {
      material = new THREE.MeshStandardMaterial({
        color: data.color,
        roughness: 0.8,
        metalness: 0.1
      });
    }

    var mesh = new THREE.Mesh(geometry, material);
    mesh.userData = { planetData: data, index: index };
    scene.add(mesh);

    // Create orbital line
    var orbitGeometry = new THREE.BufferGeometry();
    var orbitPoints = [];
    var segments = 256;
    for (var i = 0; i <= segments; i++) {
      var angle = (i / segments) * Math.PI * 2;
      orbitPoints.push(Math.cos(angle) * data.distance, 0, Math.sin(angle) * data.distance);
    }
    orbitGeometry.setAttribute('position', new THREE.Float32BufferAttribute(orbitPoints, 3));
    var orbitMaterial = new THREE.LineBasicMaterial({
      color: 0xffffff,
      transparent: true,
      opacity: 0.15
    });
    var orbitLine = new THREE.Line(orbitGeometry, orbitMaterial);
    scene.add(orbitLine);
    orbitalLines.push(orbitLine);

    // Create label
    var labelDiv = document.createElement('div');
    labelDiv.className = 'label';
    labelDiv.textContent = data.name;
    document.getElementById('labels-container').appendChild(labelDiv);
    labels.push({ element: labelDiv, mesh: mesh });

    // Apply axial tilt
    mesh.rotation.z = (data.axialTilt || 0) * (Math.PI / 180);

    // Random initial orbital phase
    mesh.userData.orbitPhase = Math.random() * Math.PI * 2;

    planets.push(mesh);
  }

  // ============================================================
  // Animation Loop
  // ============================================================
  function animate() {
    requestAnimationFrame(animate);

    var elapsed = clock.getElapsedTime();
    var delta = clock.getDelta();

    // Rotate Sun
    sunMesh.rotation.y = elapsed * 0.02;

    // Update planets
    planets.forEach(function(planet, index) {
      var data = planet.userData.planetData;
      var orbitSpeed = (2 * Math.PI) / (data.orbitalPeriod * 60); // Scale: 1 year = 60 seconds
      var orbitPhase = planet.userData.orbitPhase;
      var angle = orbitSpeed * elapsed + orbitPhase;

      // Orbital position
      planet.position.x = Math.cos(angle) * data.distance;
      planet.position.z = Math.sin(angle) * data.distance;

      // Self-rotation
      var rotationSpeed = (2 * Math.PI) / (Math.abs(data.rotationPeriod) * 2);
      var direction = data.rotationPeriod > 0 ? 1 : -1;
      planet.rotation.y += rotationSpeed * direction * 0.016;

      // Update label position
      updateLabelPosition(labels[index], planet);
    });

    // Update controls
    if (controls) {
      controls.update();
    }

    renderer.render(scene, camera);
  }

  function updateLabelPosition(label, planet) {
    var position = planet.position.clone();
    position.y += planet.userData.planetData.radius + 0.5;
    position.project(camera);

    var x = (position.x * 0.5 + 0.5) * container.clientWidth;
    var y = (-(position.y * 0.5) + 0.5) * container.clientHeight;

    // Check if planet is behind camera
    if (position.z > 1) {
      label.element.style.display = 'none';
    } else {
      label.element.style.display = 'block';
      label.element.style.left = (x + 10) + 'px';
      label.element.style.top = (y - 10) + 'px';
    }
  }

  // ============================================================
  // Click Handler
  // ============================================================
  function onCanvasClick(event) {
    mouse.x = (event.offsetX / container.clientWidth) * 2 - 1;
    mouse.y = -(event.offsetY / container.clientHeight) * 2 + 1;

    raycaster.setFromCamera(mouse, camera);
    var intersects = raycaster.intersectObjects(planets);

    if (intersects.length > 0) {
      var planet = intersects[0].object;
      showPlanetInfo(planet.userData.planetData);
    } else {
      clearPlanetInfo();
    }
  }

  function showPlanetInfo(data) {
    var infoDiv = document.getElementById('planet-info');
    infoDiv.innerHTML =
      '<div class="planet-detail">' +
        '<h4>' + data.name + '</h4>' +
        '<div class="detail-row"><span class="detail-label">Type:</span><span class="detail-value">' + data.type + '</span></div>' +
        '<div class="detail-row"><span class="detail-label">Diameter:</span><span class="detail-value">' + data.diameter + '</span></div>' +
        '<div class="detail-row"><span class="detail-label">Day Length:</span><span class="detail-value">' + data.dayLength + '</span></div>' +
        '<div class="detail-row"><span class="detail-label">Moons:</span><span class="detail-value">' + data.moons + '</span></div>' +
        '<div class="detail-row"><span class="detail-label">Temperature:</span><span class="detail-value">' + data.temperature + '</span></div>' +
        '<div class="detail-desc">' + data.description + '</div>' +
      '</div>';
  }

  function clearPlanetInfo() {
    document.getElementById('planet-info').innerHTML =
      '<div class="info-placeholder">Select a planet to view information</div>';
  }

  // ============================================================
  // Resize Handler
  // ============================================================
  function onResize() {
    camera.aspect = container.clientWidth / container.clientHeight;
    camera.updateProjectionMatrix();
    renderer.setSize(container.clientWidth, container.clientHeight);
  }

  // ============================================================
  // Start
  // ============================================================
  try {
    init();
    animate();
  } catch(e) {
    console.error('Solar system init failed:', e);
    container.innerHTML = '<div style="color:red;padding:20px;">Failed to initialize: ' + e.message + '</div>';
  }

})();

