function createSaturnRings(innerMesh, planetRadius) {
  var innerRadius = planetRadius * 1.4;
  var outerRadius = planetRadius * 2.5;
  var ringGeometry = new THREE.RingGeometry(innerRadius, outerRadius, 64);

  // Create ring texture procedurally
  var canvas = document.createElement('canvas');
  canvas.width = 256;
  canvas.height = 1;
  var ctx = canvas.getContext('2d');
  var gradient = ctx.createLinearGradient(0, 0, 256, 0);
